// 2. function createUser(id, role?)
// Your code here
   // Use ?? for default role
   // Return object with email `user_${id}@test.com`

// 3. Create user (id: 5, role: "admin")
// Your code here

// 4. result = user.email

challenges.solution:
interface User {
  id: number;
  email: string;
  role: "admin" | "guest";
}
function createUser(id: number, role?: "admin" | "guest"): User {
  return {
    id,
    email: `user_${id}@test.com`,
    role: role ?? "guest"
  };
}
const user = createUser(5, "admin");
const result = user.email;
